import React from 'react'

export default function SearchColumn({ column }) {
    const { filterValue, setFilter } = column
  return (
    <span>
        Search { ' ' }
        <input 
            value={filterValue || ''}
            onChange={e => setFilter(e.target.value)}
         />
    </span>
  );
}
